  1→//! Stage 1 (Observe): Execute a function with pre-generated inputs and collect
  2→//! execution traces. Pure observation — no Z3 or constraint solving.
  3→//!
  4→//! The observe module provides a composable building block: given a function and
  5→//! a list of inputs, it executes each input via the language frontend and returns
  6→//! structured trace data (branch coverage, line coverage, side effects, discovery
  7→//! attribution). Callers are responsible for generating inputs (random, boundary,
  8→//! user-provided) before calling into this module.
  9→
 10→use std::collections::HashSet;
 11→use std::time::{Duration, Instant};
 12→
 13→use serde::{Deserialize, Serialize};
 14→
 15→use crate::protocol::SetupLevel;
 16→use crate::protocol::SetupContextStack;
 17→use crate::coverage_metrics::DiscoveryMethod;
 18→use crate::explorer::{
 19→    classify_error_intent, frontend_supports, path_hash, send_setup, send_teardown,
 20→    ExecutionSummary, ExploreError, LoopBuckets, ObservationOutput,
 21→};
 22→use crate::frontend::{Frontend, FrontendError};
 23→use crate::orchestrator::FrontendCapabilities;
 24→use crate::protocol::{
 25→    Command as ProtoCommand, ExecuteResult, FunctionAnalysis, MockConfig, ResponseResult,
 26→};
 27→
 28→/// Errors that can occur during observation.
 29→#[derive(Debug, thiserror::Error)]
 30→pub enum ObserveError {
 31→    #[error("frontend error: {0}")]
 32→    Frontend(#[from] FrontendError),
 33→    #[error("unexpected response from frontend: {0}")]
 34→    UnexpectedResponse(String),
 35→    #[error("instrumentation failed: {0}")]
 36→    InstrumentationFailed(String),
 37→}
 38→
 39→impl From<ExploreError> for ObserveError {
 40→    fn from(e: ExploreError) -> Self {
 41→        match e {
 42→            ExploreError::Frontend(fe) => Self::Frontend(fe),
 43→            ExploreError::UnexpectedResponse(msg) => Self::UnexpectedResponse(msg),
 44→        }
 45→    }
 46→}
 47→
 48→/// Configuration for the observe stage. Contains only execution-related settings;
 49→/// input generation is the caller's responsibility.
 50→#[derive(Debug, Clone)]
 51→pub struct ObserveConfig {
 52→    /// Path to the source file (needed for instrumentation).
 53→    pub file: String,
 54→    /// Mock configurations to pass to Execute commands.
 55→    pub mocks: Vec<MockConfig>,
 56→    /// Path to the setup file, if configured.
 57→    pub setup_file: Option<String>,
 58→    /// When to run setup relative to executions.
 59→    pub setup_level: SetupLevel,
 60→    /// Frontend capabilities (used to gate setup/teardown commands).
 61→    pub capabilities: FrontendCapabilities,
 62→    /// Detected project root directory.
 63→    pub project_root: Option<String>,
 64→    /// Iteration count bucket boundaries for loop-aware path hashing.
 65→    pub loop_buckets: LoopBuckets,
 66→    /// Wall-clock timeout for the entire observation phase.
 67→    pub timeout: Option<Duration>,
 68→    /// Skip the Instrument command (caller already instrumented).
 69→    pub skip_instrument: bool,
 70→}
 71→
 72→impl From<&crate::explorer::ExploreConfig> for ObserveConfig {
 73→    fn from(ec: &crate::explorer::ExploreConfig) -> Self {
 74→        Self {
 75→            file: ec.file.clone(),
 76→            mocks: ec.mocks.clone(),
 77→            setup_file: ec.setup_file.clone(),
 78→            setup_level: ec.setup_level,
 79→            capabilities: ec.capabilities.clone(),
 80→            project_root: ec.project_root.clone(),
 81→            loop_buckets: ec.loop_buckets.clone(),
 82→            timeout: ec.timeout_explore,
 83→            skip_instrument: false,
 84→        }
 85→    }
 86→}
 87→
 88→/// Raw observation results from executing a batch of inputs.
 89→/// Lighter-weight than `ObservationOutput` — no function metadata or summary.
 90→#[derive(Debug, Serialize, Deserialize)]
 91→pub struct BatchObservation {
 92→    /// Every execution result paired with its inputs and mock configs.
 93→    pub raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)>,
 94→    /// Hashes of unique execution paths observed.
 95→    #[serde(skip)]
 96→    pub unique_path_hashes: HashSet<u64>,
 97→    /// Source lines covered across all executions.
 98→    #[serde(skip)]
 99→    pub lines_covered: HashSet<u32>,
100→    /// Per-branch discovery attribution: which branch_id was first seen.
101→    pub discoveries: Vec<(u32, DiscoveryMethod)>,
102→    /// Summaries of executions that discovered new paths.
103→    pub new_path_executions: Vec<ExecutionSummary>,
104→}
105→
106→/// Execute a batch of inputs against an already-instrumented function.
107→///
108→/// This is the lowest-level observation primitive: no instrumentation, no
109→/// setup/teardown lifecycle. The caller manages those concerns.
110→///
111→/// Each input vector is executed sequentially. Returns raw execution data,
112→/// path hashes, line coverage, and discovery attribution.
113→pub async fn observe_batch(
114→    frontend: &mut Frontend,
115→    function_name: &str,
116→    inputs: Vec<Vec<serde_json::Value>>,
117→    mocks: &[MockConfig],
118→    setup_context: Option<&SetupContextStack>,
119→    loop_buckets: &LoopBuckets,
120→    timeout: Option<Duration>,
121→) -> Result<BatchObservation, ObserveError> {
122→    let mut seen_paths: HashSet<u64> = HashSet::new();
123→    let mut all_lines: HashSet<u32> = HashSet::new();
124→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
125→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
126→    let mut new_path_executions: Vec<ExecutionSummary> = Vec::new();
127→    let mut raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)> = Vec::new();
128→
129→    let start = Instant::now();
130→
131→    for input in inputs {
132→        if timeout.is_some_and(|t| start.elapsed() >= t) {
133→            break;
134→        }
135→
136→        let response = frontend
137→            .send(ProtoCommand::Execute {
138→                function: function_name.to_string(),
139→                inputs: input.clone(),
140→                mocks: mocks.to_vec(),
141→                setup_context: setup_context.cloned(),
142→            })
143→            .await?;
144→
145→        let exec_result = match response.result {
146→            ResponseResult::Execute(result) => *result,
147→            ResponseResult::Error { code, message, .. } => {
148→                return Err(ObserveError::UnexpectedResponse(format!(
149→                    "execute error ({code:?}): {message}"
150→                )));
151→            }
152→            other => {
153→                return Err(ObserveError::UnexpectedResponse(format!(
154→                    "expected Execute response, got {other:?}"
155→                )));
156→            }
157→        };
158→
159→        for &line in &exec_result.lines_executed {
160→            all_lines.insert(line);
161→        }
162→
163→        let hash = path_hash(&exec_result, loop_buckets);
164→        let is_new = seen_paths.insert(hash);
165→
166→        for decision in &exec_result.branch_path {
167→            if seen_branch_ids.insert(decision.branch_id) {
168→                discoveries.push((decision.branch_id, DiscoveryMethod::Random));
169→            }
170→        }
171→
172→        if is_new {
173→            let error_intent = classify_error_intent(&exec_result);
174→            new_path_executions.push(ExecutionSummary {
175→                inputs: input.clone(),
176→                return_value: exec_result.return_value.clone(),
177→                thrown_error: exec_result
178→                    .thrown_error
179→                    .as_ref()
180→                    .map(|e| format!("{}: {}", e.error_type, e.message)),
181→                lines_executed: exec_result.lines_executed.clone(),
182→                is_new_path: true,
183→                error_intent,
184→            });
185→        }
186→
187→        raw_results.push((input, mocks.to_vec(), exec_result));
188→    }
189→
190→    Ok(BatchObservation {
191→        raw_results,
192→        unique_path_hashes: seen_paths,
193→        lines_covered: all_lines,
194→        discoveries,
195→        new_path_executions,
196→    })
197→}
