225→/// Scope-aware path hash that collapses repeated loop/call scopes.
226→///
227→/// Parses the flat trace into a tree of nested scopes, then for each scope_id
228→/// that appears multiple times at the same nesting level, collapses all
229→/// repetitions to a single sorted set of unique `(branch_id, taken)` pairs.
230→/// When `buckets` is non-empty, each distinct profile is also paired with
231→/// its iteration-count bucket so that different iteration counts produce
232→/// different hashes.
233→fn scope_aware_hash(events: &[crate::execution_record::TraceEvent], buckets: &LoopBuckets) -> u64 {
234→    use crate::execution_record::{ScopeEvent, TraceEvent};
235→    use std::collections::BTreeSet;
236→
237→    /// Discriminant tag for scope enter/exit matching.
238→    #[derive(Clone, Copy, PartialEq)]
239→    enum ScopeKind {
240→        Loop(u32),
241→        Call(u32),
242→    }
243→
244→    /// A sorted branch profile from one loop/call iteration.
245→    type BranchProfile = Vec<(u32, bool)>;
246→
247→    /// A profile paired with its optional iteration-count bucket.
248→    type ProfileWithBucket = (BranchProfile, Option<u32>);
249→
250→    /// Collapsed representation of a scope's content for hashing.
251→    #[derive(Hash)]
252→    enum CollapsedItem {
253→        /// A branch decision outside any scope at this level.
254→        Branch { branch_id: u32, taken: bool },
255→        /// A collapsed scope: set of distinct per-iteration branch profiles,
256→        /// each paired with its iteration-count bucket (or `None` when
257→        /// bucketing is disabled, preserving backward-compat hashing).
258→        Scope { scope_tag: u64, profile_buckets: Vec<ProfileWithBucket> },
259→    }
260→
261→    fn is_matching_exit(event: &TraceEvent, kind: ScopeKind) -> bool {
262→        match (kind, event) {
263→            (ScopeKind::Loop(id), TraceEvent::Scope { event: ScopeEvent::LoopExit { loop_id } }) => *loop_id == id,
264→            (ScopeKind::Call(id), TraceEvent::Scope { event: ScopeEvent::CallExit { call_site_id } }) => *call_site_id == id,
265→            _ => false,
266→        }
267→    }
268→
269→    /// Convert accumulated per-scope profile maps into `CollapsedItem::Scope`
270→    /// entries appended to `items`. Called at both the normal end of `collapse()`
271→    /// and the early return on parent-scope exit — without this, nested scopes
272→    /// would be invisible to their parent's branch profile.
273→    fn emit_scope_items(
274→        items: &mut Vec<CollapsedItem>,
275→        loop_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
276→        call_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
277→        buckets: &LoopBuckets,
278→    ) {
279→        let mut scope_ids: Vec<(u64, Vec<ProfileWithBucket>)> = Vec::new();
280→        for (id, profiles) in loop_profiles {
281→            let tag = (*id as u64) | (1u64 << 32);
282→            let mut sorted: Vec<ProfileWithBucket> = profiles
283→                .iter()
284→                .map(|(profile, &count)| {
285→                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
286→                    (profile.clone(), bucket)
287→                })
288→                .collect();
289→            sorted.sort();
290→            scope_ids.push((tag, sorted));
291→        }
292→        for (id, profiles) in call_profiles {
293→            let tag = (*id as u64) | (2u64 << 32);
294→            let mut sorted: Vec<ProfileWithBucket> = profiles
295→                .iter()
296→                .map(|(profile, &count)| {
297→                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
298→                    (profile.clone(), bucket)
299→                })
300→                .collect();
301→            sorted.sort();
302→            scope_ids.push((tag, sorted));
303→        }
304→        scope_ids.sort_by_key(|(tag, _)| *tag);
305→        for (scope_tag, profile_buckets) in scope_ids {
306→            items.push(CollapsedItem::Scope { scope_tag, profile_buckets });
307→        }
308→    }
309→
310→    fn collapse(events: &[TraceEvent], buckets: &LoopBuckets) -> (Vec<CollapsedItem>, usize) {
311→        let mut items: Vec<CollapsedItem> = Vec::new();
312→        let mut loop_profiles: HashMap<u32, HashMap<BranchProfile, u32>> = HashMap::new();
313→        let mut call_profiles: HashMap<u32, HashMap<BranchProfile, u32>> = HashMap::new();
314→
315→        let mut i = 0;
316→        while i < events.len() {
317→            match &events[i] {
318→                TraceEvent::Branch { decision } => {
319→                    items.push(CollapsedItem::Branch {
320→                        branch_id: decision.branch_id,
321→                        taken: decision.taken,
322→                    });
323→                    i += 1;
324→                }
325→                TraceEvent::Scope { event } => {
326→                    let (kind, is_enter) = match event {
327→                        ScopeEvent::LoopEnter { loop_id } => (ScopeKind::Loop(*loop_id), true),
328→                        ScopeEvent::LoopExit { loop_id } => (ScopeKind::Loop(*loop_id), false),
329→                        ScopeEvent::CallEnter { call_site_id } => (ScopeKind::Call(*call_site_id), true),
330→                        ScopeEvent::CallExit { call_site_id } => (ScopeKind::Call(*call_site_id), false),
331→                    };
332→
333→                    if !is_enter {
