106→/// Execute a batch of inputs against an already-instrumented function.
107→///
108→/// This is the lowest-level observation primitive: no instrumentation, no
109→/// setup/teardown lifecycle. The caller manages those concerns.
110→///
111→/// Each input vector is executed sequentially. Returns raw execution data,
112→/// path hashes, line coverage, and discovery attribution.
113→pub async fn observe_batch(
114→    frontend: &mut Frontend,
115→    function_name: &str,
116→    inputs: Vec<Vec<serde_json::Value>>,
117→    mocks: &[MockConfig],
118→    setup_context: Option<&SetupContextStack>,
119→    loop_buckets: &LoopBuckets,
120→    timeout: Option<Duration>,
121→) -> Result<BatchObservation, ObserveError> {
122→    let mut seen_paths: HashSet<u64> = HashSet::new();
123→    let mut all_lines: HashSet<u32> = HashSet::new();
124→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
125→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
126→    let mut new_path_executions: Vec<ExecutionSummary> = Vec::new();
127→    let mut raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)> = Vec::new();
128→
129→    let start = Instant::now();
130→
131→    for input in inputs {
132→        if timeout.is_some_and(|t| start.elapsed() >= t) {
133→            break;
134→        }
135→
136→        let response = frontend
137→            .send(ProtoCommand::Execute {
138→                function: function_name.to_string(),
139→                inputs: input.clone(),
140→                mocks: mocks.to_vec(),
141→                setup_context: setup_context.cloned(),
142→            })
143→            .await?;
144→
145→        let exec_result = match response.result {
146→            ResponseResult::Execute(result) => *result,
147→            ResponseResult::Error { code, message, .. } => {
148→                return Err(ObserveError::UnexpectedResponse(format!(
149→                    "execute error ({code:?}): {message}"
150→                )));
151→            }
152→            other => {
153→                return Err(ObserveError::UnexpectedResponse(format!(
154→                    "expected Execute response, got {other:?}"
155→                )));
156→            }
157→        };
158→
159→        for &line in &exec_result.lines_executed {
160→            all_lines.insert(line);
161→        }
162→
163→        let hash = path_hash(&exec_result, loop_buckets);
164→        let is_new = seen_paths.insert(hash);
165→
166→        for decision in &exec_result.branch_path {
167→            if seen_branch_ids.insert(decision.branch_id) {
168→                discoveries.push((decision.branch_id, DiscoveryMethod::Random));
169→            }
170→        }
171→
172→        if is_new {
173→            let error_intent = classify_error_intent(&exec_result);
174→            new_path_executions.push(ExecutionSummary {
175→                inputs: input.clone(),
176→                return_value: exec_result.return_value.clone(),
177→                thrown_error: exec_result
178→                    .thrown_error
179→                    .as_ref()
180→                    .map(|e| format!("{}: {}", e.error_type, e.message)),
181→                lines_executed: exec_result.lines_executed.clone(),
182→                is_new_path: true,
183→                error_intent,
184→            });
185→        }
186→
187→        raw_results.push((input, mocks.to_vec(), exec_result));
188→    }
189→
190→    Ok(BatchObservation {
191→        raw_results,
192→        unique_path_hashes: seen_paths,
193→        lines_covered: all_lines,
194→        discoveries,
195→        new_path_executions,
196→    })
197→}
