414→/// Result of trying to observe a single worklist entry.
415→enum ObserveOneResult {
416→    /// Entry was executed and produced an observation.
417→    Observed(Box<Observation>),
418→    /// Entry was skipped by triage prediction.
419→    TriageSkipped,
420→    /// Frontend returned an error or unexpected response — entry skipped.
421→    FrontendSkipped,
422→    /// A termination budget was hit before executing.
423→    Terminated(TerminationReason),
424→}
425→
426→/// Execute a single worklist entry and classify the result.
427→///
428→/// Returns an `Observation` with path classification, or a skip/termination
429→/// indicator. The caller is responsible for updating coverage state afterward.
430→#[allow(clippy::too_many_arguments)] // setup_context needed for parity with explorer
431→async fn observe_one(
432→    entry: &WorklistEntry,
433→    frontend: &mut Frontend,
434→    function_name: &str,
435→    config: &ExploreConfig,
436→    covered_paths: &mut HashSet<u64>,
437→    triage_state: &mut TriageState,
438→    budget: &ExploreBudget,
439→    setup_context: &Option<SetupContextStack>,
440→) -> Result<ObserveOneResult, ExploreError> {
441→    // Check termination budgets.
442→    if budget.unique_paths >= config.max_iterations {
443→        return Ok(ObserveOneResult::Terminated(TerminationReason::MaxIterations));
444→    }
445→    if budget.total_executions >= config.max_executions {
446→        return Ok(ObserveOneResult::Terminated(TerminationReason::MaxExecutions));
447→    }
448→    if let Some(timeout) = config.timeout_explore
449→        && budget.explore_start.elapsed() >= timeout
450→    {
451→        return Ok(ObserveOneResult::Terminated(TerminationReason::TimeoutExplore));
452→    }
453→    if config.plateau_threshold > 0 && budget.plateau_counter >= config.plateau_threshold {
454→        return Ok(ObserveOneResult::Terminated(TerminationReason::CoveragePlateau));
455→    }
456→
457→    // Triage: predict whether this input will produce a novel path.
458→    let is_sampled_skip = if entry.source != InputSource::UserProvided {
459→        let verdict = triage_state.triage_candidate(&entry.inputs, covered_paths);
460→        triage_state.record_verdict(&verdict);
461→        if verdict == TriageVerdict::Skip {
462→            if triage_state.should_sample() {
463→                true
464→            } else {
465→                return Ok(ObserveOneResult::TriageSkipped);
466→            }
467→        } else {
468→            false
469→        }
470→    } else {
471→        false
472→    };
473→
474→    // Use entry-level mocks when available, falling back to config.mocks.
475→    let effective_mocks = if entry.mock_values.is_empty() {
476→        &config.mocks
477→    } else {
478→        &entry.mock_values
479→    };
480→
481→    // Execute concretely via the frontend.
482→    let response = frontend
483→        .send(Command::Execute {
484→            function: function_name.to_string(),
485→            inputs: entry.inputs.clone(),
486→            mocks: effective_mocks.clone(),
487→            setup_context: setup_context.clone(),
488→        })
489→        .await?;
490→
491→    let exec_result = match response.result {
492→        ResponseResult::Execute(result) => *result,
493→        ResponseResult::Error { message, .. } => {
494→            log::warn!("frontend error during execute: {message}");
495→            return Ok(ObserveOneResult::FrontendSkipped);
496→        }
497→        _ => return Ok(ObserveOneResult::FrontendSkipped),
498→    };
499→
500→    let path_id = hash_branch_path(&exec_result.branch_path);
501→
502→    // Validate sampled skip prediction before modifying covered_paths.
503→    if is_sampled_skip {
504→        let already_covered = covered_paths.contains(&path_id);
505→        triage_state.record_sample(0, if already_covered { 0 } else { 1 });
506→    }
507→
508→    let is_new_path = covered_paths.insert(path_id);
509→    if is_new_path {
510→        triage_state.update(&exec_result.branch_path);
511→    }
512→
513→    Ok(ObserveOneResult::Observed(Box::new(Observation {
514→        inputs: entry.inputs.clone(),
515→        result: exec_result,
516→        source: entry.source,
517→        path_id,
518→        is_new_path,
519→        is_sampled_skip,
520→        mock_values: entry.mock_values.clone(),
521→    })))
522→}
