 88→/// Raw observation results from executing a batch of inputs.
 89→/// Lighter-weight than `ObservationOutput` — no function metadata or summary.
 90→#[derive(Debug, Serialize, Deserialize)]
 91→pub struct BatchObservation {
 92→    /// Every execution result paired with its inputs and mock configs.
 93→    pub raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)>,
 94→    /// Hashes of unique execution paths observed.
 95→    #[serde(skip)]
 96→    pub unique_path_hashes: HashSet<u64>,
 97→    /// Source lines covered across all executions.
 98→    #[serde(skip)]
 99→    pub lines_covered: HashSet<u32>,
100→    /// Per-branch discovery attribution: which branch_id was first seen.
101→    pub discoveries: Vec<(u32, DiscoveryMethod)>,
102→    /// Summaries of executions that discovered new paths.
