364→
365→                    // Increment iteration count for this (scope_id, profile) pair
366→                    match kind {
367→                        ScopeKind::Loop(id) => {
368→                            *loop_profiles.entry(id).or_default().entry(profile_vec).or_insert(0) += 1;
369→                        }
370→                        ScopeKind::Call(id) => {
